    "path": "captain-tsubasa-rise-trainer/README.md",
    "content": "# Captain Tsubasa: Rise of New Champions Trainer\n\nA memory trainer for the game **Captain Tsubasa: Rise of New Champions**. This tool allows you to modify in-game values such as player stats, team spirit, and match timer.\n\n## Features\n- **Player Stats Editor**: Modify speed, power, and technique.\n- **Team Spirit Modifier**: Adjust team spirit to max or any value.\n- **Match Timer Control**: Freeze or set the match timer.\n- **Process Attach**: Automatically attaches to the game process.\n\n## Requirements\n- .NET 6.0 or later\n- Windows (due to memory API usage)\n\n## Build & Run\n```bash\ndotnet build\n```\n\n## Usage\n1. Launch the game.\n2. Run the trainer.\n3. Select the desired modifications.\n\n## Project Structure\n- `TrainerCore/` - Core logic for memory manipulation.\n- `TrainerUI/` - Console-based user interface.\n- `tests/` - Unit tests.\n\n## License\nMIT\n"
  },
  {
    "path": "captain-tsubasa-rise-trainer/src/TrainerCore/GameMemoryManager.cs",
    "content": "using System;\nusing System.Diagnostics;\nusing System.Runtime.InteropServices;\n\nnamespace CaptainTsubasaRiseTrainer.TrainerCore\n{\n    /// <summary>\n    /// Manages low-level memory operations for the game process.\n    /// Provides methods to read and write process memory for Captain Tsubasa: Rise of New Champions.\n    /// </summary>\n    public class GameMemoryManager : IDisposable\n    {\n        private Process _gameProcess;\n        private IntPtr _processHandle;\n        private bool _disposed;\n\n        // Win32 API imports for memory manipulation\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern IntPtr OpenProcess(uint dwDesiredAccess, bool bInheritHandle, int dwProcessId);\n\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern bool ReadProcessMemory(IntPtr hProcess, IntPtr lpBaseAddress, byte[] lpBuffer, int dwSize, out int lpNumberOfBytesRead);\n\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern bool WriteProcessMemory(IntPtr hProcess, IntPtr lpBaseAddress, byte[] lpBuffer, int dwSize, out int lpNumberOfBytesWritten);\n\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern bool CloseHandle(IntPtr hObject);\n\n        private const uint PROCESS_VM_READ = 0x0010;\n        private const uint PROCESS_VM_WRITE = 0x0020;\n        private const uint PROCESS_VM_OPERATION = 0x0008;\n        private const uint PROCESS_QUERY_INFORMATION = 0x0400;\n\n        /// <summary>\n        /// Initializes a new instance of the <see cref=\"GameMemoryManager\"/> class.\n        /// Automatically attaches to the game process if it is running.\n        /// </summary>\n        public GameMemoryManager()\n        {\n            AttachToProcess();\n        }\n\n        /// <summary>\n        /// Attaches to the Captain Tsubasa: Rise of New Champions process.\n        /// </summary>\n        /// <exception cref=\"InvalidOperationException\">Thrown if the game process is not found.</exception>\n        private void AttachToProcess()\n        {\n            var processes = Process.GetProcessesByName(\"CaptainTsubasaRise\");\n            if (processes.Length == 0)\n            {\n                throw new InvalidOperationException(\"Game process not found. Please ensure the game is running.\");\n            }\n\n            _gameProcess = processes[0];\n            _processHandle = OpenProcess(PROCESS_VM_READ | PROCESS_VM_WRITE | PROCESS_VM_OPERATION | PROCESS_QUERY_INFORMATION, false, _gameProcess.Id);\n\n            if (_processHandle == IntPtr.Zero)\n            {\n                throw new InvalidOperationException(\"Failed to open process handle. Run as administrator.\");\n            }\n        }\n\n        /// <summary>\n        /// Reads a block of memory from the game process at the specified address.\n        /// </summary>\n        /// <param name=\"address\">The base address to read from.</param>\n        /// <param name=\"size\">Number of bytes to read.</param>\n        /// <returns>Byte array containing the read data.</returns>\n        public byte[] ReadMemory(IntPtr address, int size)\n        {\n            byte[] buffer = new byte[size];\n            if (!ReadProcessMemory(_processHandle, address, buffer, size, out int bytesRead))\n            {\n                throw new InvalidOperationException($\"Failed to read memory at 0x{address.ToInt64():X}. Error code: {Marshal.GetLastWin32Error()}\");\n            }\n            return buffer;\n        }\n\n        /// <summary>\n        /// Writes a block of memory to the game process at the specified address.\n        /// </summary>\n        /// <param name=\"address\">The base address to write to.</param>\n        /// <param name=\"data\">Byte array containing the data to write.</param>\n        public void WriteMemory(IntPtr address, byte[] data)\n        {\n            if (!WriteProcessMemory(_processHandle, address, data, data.Length, out int bytesWritten))\n            {\n                throw new InvalidOperationException($\"Failed to write memory at 0x{address.ToInt64():X}. Error code: {Marshal.GetLastWin32Error()}\");\n            }\n        }\n\n        /// <summary>\n        /// Reads an integer value from the specified memory address.\n        /// </summary>\n        /// <param name=\"address\">The memory address.</param>\n        /// <returns>Integer value read.</returns>\n        public int ReadInt32(IntPtr address)\n        {\n            byte[] data = ReadMemory(address, 4);\n            return BitConverter.ToInt32(data, 0);\n        }\n\n        /// <summary>\n        /// Writes an integer value to the specified memory address.\n        /// </summary>\n        /// <param name=\"address\">The memory address.</param>\n        /// <param name=\"value\">Integer value to write.</param>\n        public void WriteInt32(IntPtr address, int value)\n        {\n            byte[] data = BitConverter.GetBytes(value);\n            WriteMemory(address, data);\n        }\n\n        /// <summary>\n        /// Reads a float value from the specified memory address.\n        /// </summary>\n        /// <param name=\"address\">The memory address.</param>\n        /// <returns>Float value read.</returns>\n        public float ReadFloat(IntPtr address)\n        {\n            byte[] data = ReadMemory(address, 4);\n            return BitConverter.ToSingle(data, 0);\n        }\n\n        /// <summary>\n        /// Writes a float value to the specified memory address.\n        /// </summary>\n        /// <param name=\"address\">The memory address.</param>\n        /// <param name=\"value\">Float value to write.</param>\n        public void WriteFloat(IntPtr address, float value)\n        {\n            byte[] data = BitConverter.GetBytes(value);\n            WriteMemory(address, data);\n        }\n\n        /// <summary>\n        /// Disposes the process handle and releases resources.\n        /// </summary>\n        public void Dispose()\n        {\n            if (!_disposed && _processHandle != IntPtr.Zero)\n            {\n                CloseHandle(_processHandle);\n                _processHandle = IntPtr.Zero;\n                _disposed = true;\n            }\n        }\n    }\n}\n"
  },
