    "path": "captain-tsubasa-rise-trainer/src/TrainerCore/MemoryOffsets.cs",
    "content": "using System;\n\nnamespace CaptainTsubasaRiseTrainer.TrainerCore\n{\n    /// <summary>\n    /// Contains known memory offsets for Captain Tsubasa: Rise of New Champions (version 1.0).\n    /// These offsets are used to locate specific game variables in the process memory.\n    /// Note: Offsets may change after game updates; adjust accordingly.\n    /// </summary>\n    public static class MemoryOffsets\n    {\n        // Base address offsets (relative to game module base)\n        private static readonly IntPtr ModuleBase = IntPtr.Zero; // Set dynamically\n\n        /// <summary>\n        /// Offset for player speed stat (float).\n        /// </summary>\n        public static IntPtr PlayerSpeedOffset => new IntPtr(0x00A3B4C0);\n\n        /// <summary>\n        /// Offset for player power stat (float).\n        /// </summary>\n        public static IntPtr PlayerPowerOffset => new IntPtr(0x00A3B4C4);\n\n        /// <summary>\n        /// Offset for player technique stat (float).\n        /// </summary>\n        public static IntPtr PlayerTechniqueOffset => new IntPtr(0x00A3B4C8);\n\n        /// <summary>\n        /// Offset for team spirit value (int32).\n        /// </summary>\n        public static IntPtr TeamSpiritOffset => new IntPtr(0x00A3B5A0);\n\n        /// <summary>\n        /// Offset for match timer in seconds (float).\n        /// </summary>\n        public static IntPtr MatchTimerOffset => new IntPtr(0x00A3B6E0);\n\n        /// <summary>\n        /// Offset for ball possession flag (int32, 1 = player has ball, 0 = opponent).\n        /// </summary>\n        public static IntPtr BallPossessionOffset => new IntPtr(0x00A3B7F0);\n\n        /// <summary>\n        /// Gets the full address by adding the module base.\n        /// This method can be extended to support dynamic module base resolution.\n        /// </summary>\n        /// <param name=\"offset\">The offset from module base.</param>\n        /// <returns>Full memory address.</returns>\n        public static IntPtr GetFullAddress(IntPtr offset)\n        {\n            // In a real scenario, we would add the module base address\n            // For simplicity, we assume offsets are absolute for now\n            return offset;\n        }\n    }\n}\n"
  },
