    "path": "captain-tsubasa-rise-trainer/src/TrainerUI/Program.cs",
    "content": "using System;\nusing CaptainTsubasaRiseTrainer.TrainerCore;\n\nnamespace CaptainTsubasaRiseTrainer.TrainerUI\n{\n    /// <summary>\n    /// Main entry point for the Captain Tsubasa: Rise of New Champions Trainer console application.\n    /// Provides a simple interactive menu for modifying game values.\n    /// </summary>\n    class Program\n    {\n        static void Main(string[] args)\n        {\n            Console.WriteLine(\"Captain Tsubasa: Rise of New Champions Trainer\");\n            Console.WriteLine(\"==============================================\");\n            Console.WriteLine();\n\n            try\n            {\n                using (var memoryManager = new GameMemoryManager())\n                {\n                    Console.WriteLine(\"Successfully attached to game process.\");\n                    Console.WriteLine();\n\n                    bool exit = false;\n                    while (!exit)\n                    {\n                        DisplayMenu();\n                        string input = Console.ReadLine();\n                        Console.WriteLine();\n\n                        switch (input)\n                        {\n                            case \"1\":\n                                ModifyPlayerStats(memoryManager);\n                                break;\n                            case \"2\":\n                                ModifyTeamSpirit(memoryManager);\n                                break;\n                            case \"3\":\n                                ModifyMatchTimer(memoryManager);\n                                break;\n                            case \"4\":\n                                Console.WriteLine(\"Exiting trainer. Goodbye!\");\n                                exit = true;\n                                break;\n                            default:\n                                Console.WriteLine(\"Invalid option. Please try again.\");\n                                break;\n                        }\n                        Console.WriteLine();\n                    }\n                }\n            }\n            catch (Exception ex)\n            {\n                Console.WriteLine($\"Error: {ex.Message}\");\n                Console.WriteLine(\"Press any key to exit...\");\n                Console.ReadKey();\n            }\n        }\n\n        /// <summary>\n        /// Displays the main menu options.\n        /// </summary>\n        static void DisplayMenu()\n        {\n            Console.WriteLine(\"Select an option:\");\n            Console.WriteLine(\"1. Modify Player Stats (Speed, Power, Technique)\");\n            Console.WriteLine(\"2. Modify Team Spirit\");\n            Console.WriteLine(\"3. Modify Match Timer\");\n            Console.WriteLine(\"4. Exit\");\n            Console.Write(\"Option: \");\n        }\n\n        /// <summary>\n        /// Allows the user to modify player speed, power, and technique.\n        /// </summary>\n        /// <param name=\"memoryManager\">The game memory manager instance.</param>\n        static void ModifyPlayerStats(GameMemoryManager memoryManager)\n        {\n            Console.WriteLine(\"--- Player Stats Editor ---\");\n\n            Console.Write(\"Enter new Speed value (float, default 100.0): \");\n            string speedInput = Console.ReadLine();\n            float speed = string.IsNullOrEmpty(speedInput) ? 100.0f : float.Parse(speedInput);\n\n            Console.Write(\"Enter new Power value (float, default 100.0): \");\n            string powerInput = Console.ReadLine();\n            float power = string.IsNullOrEmpty(powerInput) ? 100.0f : float.Parse(powerInput);\n\n            Console.Write(\"Enter new Technique value (float, default 100.0): \");\n            string techInput = Console.ReadLine();\n            float technique = string.IsNullOrEmpty(techInput) ? 100.0f : float.Parse(techInput);\n\n            try\n            {\n                memoryManager.WriteFloat(MemoryOffsets.GetFullAddress(MemoryOffsets.PlayerSpeedOffset), speed);\n                memoryManager.WriteFloat(MemoryOffsets.GetFullAddress(MemoryOffsets.PlayerPowerOffset), power);\n                memoryManager.WriteFloat(MemoryOffsets.GetFullAddress(MemoryOffsets.PlayerTechniqueOffset), technique);\n                Console.WriteLine(\"Player stats updated successfully.\");\n            }\n            catch (Exception ex)\n            {\n                Console.WriteLine($\"Failed to update player stats: {ex.Message}\");\n            }\n        }\n\n        /// <summary>\n        /// Allows the user to modify team spirit value.\n        /// </summary>\n        /// <param name=\"memoryManager\">The game memory manager instance.</param>\n        static void ModifyTeamSpirit(GameMemoryManager memoryManager)\n        {\n            Console.WriteLine(\"--- Team Spirit Editor ---\");\n            Console.Write(\"Enter new Team Spirit value (int, max 100): \");\n            string input = Console.ReadLine();\n            int spirit = string.IsNullOrEmpty(input) ? 100 : int.Parse(input);\n            spirit = Math.Clamp(spirit, 0, 100);\n\n            try\n            {\n                memoryManager.WriteInt32(MemoryOffsets.GetFullAddress(MemoryOffsets.TeamSpiritOffset), spirit);\n                Console.WriteLine(\"Team spirit updated successfully.\");\n            }\n            catch (Exception ex)\n            {\n                Console.WriteLine($\"Failed to update team spirit: {ex.Message}\");\n            }\n        }\n\n        /// <summary>\n        /// Allows the user to modify the match timer.\n        /// </summary>\n        /// <param name=\"memoryManager\">The game memory manager instance.</param>\n        static void ModifyMatchTimer(GameMemoryManager memoryManager)\n        {\n            Console.WriteLine(\"--- Match Timer Editor ---\");\n            Console.Write(\"Enter new match timer value in seconds (float, e.g., 600 for 10 min): \");\n            string input = Console.ReadLine();\n            float timer = string.IsNullOrEmpty(input) ? 600.0f : float.Parse(input);\n\n            try\n            {\n                memoryManager.WriteFloat(MemoryOffsets.GetFullAddress(MemoryOffsets.MatchTimerOffset), timer);\n                Console.WriteLine(\"Match timer updated successfully.\");\n            }\n            catch (Exception ex)\n            {\n                Console.WriteLine($\"Failed to update match timer: {ex.Message}\");\n            }\n        }\n    }\n}\n"
  },
