    "content": "using System;\nusing Xunit;\nusing CaptainTsubasaRiseTrainer.TrainerCore;\n\nnamespace CaptainTsubasaRiseTrainer.Tests\n{\n    /// <summary>\n    /// Unit tests for the TrainerCore components.\n    /// These tests verify the logic of memory offset definitions and address calculation.\n    /// Note: Actual memory read/write tests require the game process to be running.\n    /// </summary>\n    public class TrainerCoreTests\n    {\n        [Fact]\n        public void MemoryOffsets_AllOffsetsAreNonZero()\n        {\n            // Arrange & Act\n            var speedOffset = MemoryOffsets.PlayerSpeedOffset;\n            var powerOffset = MemoryOffsets.PlayerPowerOffset;\n            var techniqueOffset = MemoryOffsets.PlayerTechniqueOffset;\n            var spiritOffset = MemoryOff
